import{_ as a,a as d,b as i,c as t,d as o,e as n,f as l,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as r,o as p,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/federated-distributed-index.md","filePath":"fa/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"fa/Other/federated-distributed-index.md"};function b(m,e,f,g,x,q){return p(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>Federated distributed index به چند ImgBed site اجازه می‌دهد file lists را با هم share کنند.</p><p>به زبان ساده:</p><ul><li>می‌توانید selected folders از site خودتان را با دیگران share کنید.</li><li>می‌توانید به node دیگری join شوید و shared file list آن node را داخل admin panel خود sync کنید.</li><li>Federated files بیشتر برای browsing، searching و باز کردن links هستند. این files دوباره در storage خودتان upload نمی‌شوند.</li></ul><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>باز کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+a+`" alt="Local federation node" loading="lazy"></p><p>page سه tab دارد:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>enable کردن node خودتان، confirm کردن public domain، انتخاب shared folders و update کردن outbound index</td></tr><tr><td>Nodes I Joined</td><td>مدیریت ImgBed nodes دیگری که به آن‌ها join شده‌اید</td></tr><tr><td>Nodes Joining Me</td><td>مدیریت درخواست‌های دیگران برای join شدن به node شما</td></tr></tbody></table><h2 id="راه‌اندازی-اولیه" tabindex="-1">راه‌اندازی اولیه <a class="header-anchor" href="#راه‌اندازی-اولیه" aria-label="Permalink to &quot;راه‌اندازی اولیه&quot;">​</a></h2><ol><li><code>Local Node</code> را باز کنید.</li><li><code>Enable</code> را روشن کنید.</li><li>در <code>Sync folders</code>، folders موردنظر برای share را انتخاب کنید.</li><li><code>Update Outbound Index</code> را بزنید.</li><li>اگر ImgBed domain change detect کرد، پیش از ادامه confirm کنید current domain درست است.</li></ol><p>می‌توانید چند sync folder انتخاب کنید.</p><p>اگر sync folder list خالی باشد، همه folders share می‌شوند.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>public domain همان site URL است که nodes دیگر برای دسترسی به node شما استفاده می‌کنند.</p><p>ImgBed این را automatically detect می‌کند. لازم نیست دستی تایپ کنید. اولین بار که index را update می‌کنید، ImgBed می‌پرسد current access URL همان production domain است یا نه.</p><p>اگر بعداً domains را تغییر دهید، update index دوباره confirmation می‌خواهد.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders مشخص می‌کند چه files با federation nodes share شوند.</p><p>مثلاً اگر فقط این‌ها را انتخاب کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>nodes دیگر فقط files داخل این دو directories را می‌بینند.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>این کار file listی را update می‌کند که nodes دیگر می‌توانند از شما sync کنند.</p><p>وقتی استفاده کنید که:</p><ul><li>federation را برای اولین بار enable می‌کنید.</li><li>files جدیدی upload کرده‌اید که می‌خواهید share شوند.</li><li>sync folders را تغییر داده‌اید.</li><li>public domain را تغییر داده‌اید و باید confirm شود.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> جایی است که به nodes دیگر subscribe می‌کنید.</p><p><img src="`+d+'" alt="Nodes I joined" loading="lazy"></p><h3 id="ارسال-request-برای-join-شدن-به-node-دیگر" tabindex="-1">ارسال Request برای Join شدن به Node دیگر <a class="header-anchor" href="#ارسال-request-برای-join-شدن-به-node-دیگر" aria-label="Permalink to &quot;ارسال Request برای Join شدن به Node دیگر&quot;">​</a></h3><ol><li>از owner دیگر invitation link بخواهید.</li><li>آن را داخل input box paste کنید.</li><li><code>Request to Join</code> را بزنید.</li><li>منتظر بمانید owner دیگر در admin panel خود approve کند.</li></ol><p>پس از approval، node status برابر approved می‌شود.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> file lists را از nodesی که joined هستید sync می‌کند.</p><p>وقتی استفاده کنید که:</p><ul><li>owner دیگر تازه request شما را approve کرده.</li><li>owner دیگر می‌گوید shared content update شده.</li><li>می‌خواهید همه joined federation file lists را refresh کنید.</li></ul><p>برای update کردن فقط یک node، روی <code>Update Index</code> در card همان node کلیک کنید.</p><p><img src="'+i+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>اگر دیگر نمی‌خواهید nodeی را sync کنید، <code>Unsubscribe</code> را بزنید.</p><p>پس از unsubscribe، federated index آن node از local site شما حذف می‌شود.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> جایی است که requests دیگران را handle می‌کنید.</p><p><img src="'+t+'" alt="Nodes joining me" loading="lazy"></p><h3 id="ساخت-invitation-link" tabindex="-1">ساخت Invitation Link <a class="header-anchor" href="#ساخت-invitation-link" aria-label="Permalink to &quot;ساخت Invitation Link&quot;">​</a></h3><ol><li>مطمئن شوید local node enabled است.</li><li>حداقل یک بار <code>Update Outbound Index</code> را بزنید تا ImgBed public domain را confirm کند.</li><li><code>Nodes Joining Me</code> را باز کنید.</li><li><code>Reset Invitation Link</code> را بزنید.</li><li>invitation link را copy کنید و برای owner دیگر بفرستید.</li></ol><p>اگر invitation link خالی است، معمولاً public domain هنوز confirmed نشده. به <code>Local Node</code> برگردید و <code>Update Outbound Index</code> را بزنید.</p><h3 id="handle-کردن-join-requests" tabindex="-1">Handle کردن Join Requests <a class="header-anchor" href="#handle-کردن-join-requests" aria-label="Permalink to &quot;Handle کردن Join Requests&quot;">​</a></h3><p>وقتی کسی request ارسال کند، در list مربوط به <code>Nodes Joining Me</code> ظاهر می‌شود.</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>اجازه می‌دهد node دیگر shared file list شما را sync کند</td></tr><tr><td>Reject</td><td>join request را رد می‌کند</td></tr><tr><td>Delete</td><td>record تمام‌شده را حذف می‌کند</td></tr><tr><td>Check Status</td><td>بررسی می‌کند طرف مقابل هنوز این relationship را نگه داشته یا نه</td></tr></tbody></table><p>پس از approval، طرف مقابل همچنان باید <code>Update Inbound Index</code> را بزند تا shared files شما آنجا ظاهر شوند.</p><p><img src="'+o+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>بعد از approved شدن relationship، روی <code>Message</code> در node card کلیک کنید.</p><p>Messages فقط برای ارتباط درباره federation relationship است. files، tags، directories یا permissions را تغییر نمی‌دهد.</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="مشاهده-federated-files" tabindex="-1">مشاهده Federated Files <a class="header-anchor" href="#مشاهده-federated-files" aria-label="Permalink to &quot;مشاهده Federated Files&quot;">​</a></h2><p>پس از کامل شدن sync، به admin file list برگردید.</p><p>بالای page بین local files و federated files جابه‌جا شوید. در federated files می‌توانید synced content را browse کنید.</p><p>Federated files بیشتر برای viewing، searching، preview و copy کردن links هستند. چون local files نیستند، نمی‌توانید آن‌ها را از site خودتان move، delete، retag یا backup کنید.</p><p><img src="'+l+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="چرا-می‌گوید-چون-relationship-record-وجود-ندارد-باید-reapply-کنم؟" tabindex="-1">چرا می‌گوید چون Relationship Record وجود ندارد باید Reapply کنم؟ <a class="header-anchor" href="#چرا-می‌گوید-چون-relationship-record-وجود-ندارد-باید-reapply-کنم؟" aria-label="Permalink to &quot;چرا می‌گوید چون Relationship Record وجود ندارد باید Reapply کنم؟&quot;">​</a></h3><p>معمولاً یعنی طرف مقابل شما را delete کرده و record را حذف کرده است، بنابراین relationship دیگر پیدا نمی‌شود. یک join request جدید submit کنید.</p><p><img src="'+s+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="چرا-بعد-از-join-شدن-files-را-نمی‌بینم؟" tabindex="-1">چرا بعد از Join شدن Files را نمی‌بینم؟ <a class="header-anchor" href="#چرا-بعد-از-join-شدن-files-را-نمی‌بینم؟" aria-label="Permalink to &quot;چرا بعد از Join شدن Files را نمی‌بینم؟&quot;">​</a></h3><p>بررسی کنید:</p><ol><li>owner دیگر request شما را approve کرده باشد.</li><li>owner دیگر <code>Update Outbound Index</code> را زده باشد.</li><li>شما <code>Update Inbound Index</code> را زده باشید.</li><li>sync folders طرف مقابل شامل directoriesی باشد که می‌خواهد share کند.</li></ol><h3 id="وقتی-domain-change-detected-شد-چه-کنم؟" tabindex="-1">وقتی Domain Change Detected شد چه کنم؟ <a class="header-anchor" href="#وقتی-domain-change-detected-شد-چه-کنم؟" aria-label="Permalink to &quot;وقتی Domain Change Detected شد چه کنم؟&quot;">​</a></h3><p>اگر admin panel را از production domain باز کرده‌اید، confirm کنید و ادامه دهید.</p><p>اگر از temporary address استفاده می‌کنید، cancel کنید، admin panel را با production domain دوباره باز کنید و دوباره تلاش کنید.</p><h3 id="empty-sync-folder-list-یعنی-چه؟" tabindex="-1">Empty Sync Folder List یعنی چه؟ <a class="header-anchor" href="#empty-sync-folder-list-یعنی-چه؟" aria-label="Permalink to &quot;Empty Sync Folder List یعنی چه؟&quot;">​</a></h3><p>sync folder list خالی یعنی همه folders share می‌شوند.</p><p>برای share کردن فقط بعضی directories، آن folders را manual انتخاب کنید.</p><h3 id="تفاوت-outbound-و-inbound-index-updates" tabindex="-1">تفاوت Outbound و Inbound Index Updates <a class="header-anchor" href="#تفاوت-outbound-و-inbound-index-updates" aria-label="Permalink to &quot;تفاوت Outbound و Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>چیزی را update می‌کند که دیگران می‌توانند از من sync کنند</td></tr><tr><td>Update Inbound Index</td><td>چیزی را update می‌کند که من از دیگران sync کرده‌ام</td></tr></tbody></table>',78)])])}const _=r(u,[["render",b]]);export{k as __pageData,_ as default};
